# ─── Parser planning classe XLS ───────────────────────────────────────────────
def parse_planning_xls(filepath):
    try:
        wb = xlrd.open_workbook(filepath, formatting_info=True)
    except Exception as e:
        return {'nom': Path(filepath).stem, 'jours': []}
    # Prendre la première feuille non-vide (certains fichiers ont Feuil2 vide en index 0)
    ws = None
    for si in range(wb.nsheets):
        s = wb.sheet_by_index(si)
        if s.nrows > 0:
            ws = s
            break
    if ws is None:
        ws = wb.sheet_by_index(0)
    nom = Path(filepath).stem
    for c in range(ws.ncols):
        v = ws.cell_value(0, c)
        if isinstance(v, str) and len(v.strip()) > 3:
            nom = v.strip(); break
    # Si le nom extrait ne contient pas de numéro, compléter avec le numéro du nom de fichier
    if not re.search(r'\d', nom):
        m_num = re.search(r'\b(\d{1,3})\b', Path(filepath).stem)
        if m_num:
            nom = nom.rstrip() + ' ' + m_num.group(1)

    jours = []
    # Détecter toutes les lignes header (contenant des mois)
    header_rows = {}  # hrow -> list of {cj, cd, y, m}
    for r in range(ws.nrows - 1):
        row_blocks = []
        for c in range(ws.ncols):
            v = ws.cell_value(r, c)
            if isinstance(v, str):
                mn, yr = find_month_num(v)
                if mn and yr:
                    row_blocks.append({'cj': c+1, 'cd': c+2, 'y': yr, 'm': mn})
        if row_blocks:
            header_rows[r] = row_blocks

    # Trier les lignes header et déterminer la plage de lignes de chaque section
    sorted_hrows = sorted(header_rows.keys())
    blocks = []  # {cj, cd, y, m, r_start, r_end}
    for i, hr in enumerate(sorted_hrows):
        r_end = sorted_hrows[i+1] if i+1 < len(sorted_hrows) else ws.nrows
        for b in header_rows[hr]:
            blocks.append({**b, 'r_start': hr+1, 'r_end': r_end})

    for b in blocks:
        for r in range(b['r_start'], b['r_end']):
            if b['cj'] > ws.ncols or b['cd'] > ws.ncols: continue
            try:
                xf = wb.xf_list[ws.cell_xf_index(r, b['cj'])]
                rgb = wb.colour_map.get(xf.background.pattern_colour_index)
                if not colors_match(rgb): continue
            except: continue
            dv = ws.cell_value(r, b['cd'])
            dn = int(dv) if isinstance(dv, float) and dv > 0 else None
            if isinstance(dv, str) and dv.strip().isdigit(): dn = int(dv.strip())
            if not dn or not (1 <= dn <= 31): continue
            try:
                d = datetime.date(b['y'], b['m'], dn)
                if d.weekday() < 5: jours.append(d.strftime('%Y-%m-%d'))
            except: pass
    return {'nom': nom, 'jours': sorted(set(jours))}

# ─── Parser planning classe XLSX ──────────────────────────────────────────────
def parse_planning_xlsx(filepath):
    try:
        wb = load_workbook(filepath, data_only=True)
    except: return {'nom': Path(filepath).stem, 'jours': []}
    ws = wb.active
    nom = Path(filepath).stem
    for c in range(1, ws.max_column+1):
        v = ws.cell(row=1, column=c).value
        if v and isinstance(v, str) and len(v.strip()) > 3:
            nom = v.strip(); break

    jours = []
    blocks = []
    for c in range(1, ws.max_column+1):
        v = ws.cell(row=5, column=c).value
        if isinstance(v, str):
            mn, yr = find_month_num(v)
            if mn and yr:
                blocks.append({'cj': c+1, 'cd': c+2, 'y': yr, 'm': mn})

    for b in blocks:
        for r in range(6, ws.max_row+1):
            cell = ws.cell(row=r, column=b['cj'])
            bg = cell.fill.fgColor.rgb if cell.fill and cell.fill.fgColor and cell.fill.fgColor.type == 'rgb' else None
            if bg not in ('FFA6CAF0', 'A6CAF0'): continue
            dv = ws.cell(row=r, column=b['cd']).value
            dn = None
            if isinstance(dv, datetime.datetime): dn = dv.day
            elif isinstance(dv, (int, float)): dn = int(dv)
            elif isinstance(dv, str) and dv.strip().isdigit(): dn = int(dv.strip())
            if not dn or not (1 <= dn <= 31): continue
            try:
                d = datetime.date(b['y'], b['m'], dn)
                if d.weekday() < 5: jours.append(d.strftime('%Y-%m-%d'))
            except: pass
    return {'nom': nom, 'jours': sorted(set(jours))}

def parse_planning_classe(fp):
    return parse_planning_xls(fp) if Path(fp).suffix.lower() == '.xls' else parse_planning_xlsx(fp)

# ─── Parser disponibilités ────────────────────────────────────────────────────
def parse_disponibilite(filepath):
    nom = Path(filepath).stem
    dispo = {}
    try:
        wb = load_workbook(filepath, data_only=True)
        ws = wb.active
        rows = list(ws.iter_rows(values_only=True))
    except:
        return {'nom': nom, 'dispo': {}}

    if len(rows) < 3: return {'nom': nom, 'dispo': {}}

    # Extraire le nom : cherche un label "nom/prénom" sur la ligne,
    # puis prend la première valeur non-vide sur cette même ligne
    for ri in range(min(6, len(rows))):
        row = rows[ri] if rows[ri] else ()
        row_str = [v for v in row if isinstance(v, str) and v.strip()]
        has_label = any(any(k in v.lower() for k in ['nom', 'prénom', 'prenom']) for v in row_str)
        if has_label:
            for val in row_str:
                if not any(k in val.lower() for k in ['nom', 'prénom', 'prenom', 'planning', 'de :']):
                    nom = val.strip(); break
            if nom != Path(filepath).stem: break

    # Trouver la ligne contenant les en-têtes de mois (datetimes ou chaînes mois/année)
    month_row_idx = None
    for ri, row in enumerate(rows):
        if not row: continue
        if any(isinstance(v, datetime.datetime) for v in row):
            month_row_idx = ri; break
        if any(isinstance(v, str) and find_month_num(v)[0] for v in row if v):
            month_row_idx = ri; break
    if month_row_idx is None: return {'nom': nom, 'dispo': {}}

    # Détecter les blocs mois : chaque mois occupe 6 colonnes
    # Structure par bloc : [jour_abbr, jour_num, matin1, matin2, pm1, pm2]
    # La date du mois est à la colonne ci_matin1 (3ème col du bloc)
    month_blocks = []
    row_m = rows[month_row_idx]
    for ci, val in enumerate(row_m):
        mn, yr = None, None
        if isinstance(val, datetime.datetime):
            mn, yr = val.month, val.year
        elif isinstance(val, str):
            mn, yr = find_month_num(val)
        if mn and yr:
            month_blocks.append({'ci_abbr': ci - 2, 'ci_num': ci - 1,
                                  'ci_matin1': ci, 'ci_matin2': ci + 1,
                                  'ci_pm1': ci + 2, 'ci_pm2': ci + 3,
                                  'm': mn, 'y': yr})

    if not month_blocks: return {'nom': nom, 'dispo': {}}

    ign = {'sam', 'dim', 'férié', 'ferie', 'férie', 'fériés', 'nan', 'none', ''}

    for mc in month_blocks:
        for ri in range(month_row_idx + 2, len(rows)):
            row = rows[ri] if rows[ri] else ()
            ci_a = mc['ci_abbr']
            day_abbr = cell_to_str(row[ci_a]).lower() if 0 <= ci_a < len(row) else ''
            if not day_abbr or day_abbr in ign: continue
            ci_n = mc['ci_num']
            day_raw = row[ci_n] if 0 <= ci_n < len(row) else None
            dn = None
            if isinstance(day_raw, (int, float)): dn = int(day_raw)
            elif isinstance(day_raw, str) and day_raw.strip().isdigit(): dn = int(day_raw.strip())
            if not dn or not (1 <= dn <= 31): continue
            try:
                d = datetime.date(mc['y'], mc['m'], dn)
                if d.weekday() >= 5: continue
                ds = d.strftime('%Y-%m-%d')
                m1 = is_available(row[mc['ci_matin1']] if mc['ci_matin1'] < len(row) else None)
                m2 = is_available(row[mc['ci_matin2']] if mc['ci_matin2'] < len(row) else None)
                p1 = is_available(row[mc['ci_pm1']]    if mc['ci_pm1']    < len(row) else None)
                p2 = is_available(row[mc['ci_pm2']]    if mc['ci_pm2']    < len(row) else None)
                if m1 or m2 or p1 or p2:
                    dispo[ds] = {'matin1': m1, 'matin2': m2, 'pm1': p1, 'pm2': p2}
            except: pass

    return {'nom': nom, 'dispo': dispo}

# ─── Parser tableau formateurs ────────────────────────────────────────────────
def parse_tableau_formateurs(filepath):
    assignments = defaultdict(list)

    def process(rows):
        cur = None
        for row in rows:
            v0 = cell_to_str(row[0]) if row and row[0] is not None else ''
            if re.match(r'(BTS|BAC|CGC|NDRC|GPME|Master|RDC|RH|EC)\s', v0, re.I):
                cur = v0
            elif cur and v0 and len(row) > 1 and row[1]:
                mat = cell_to_str(row[1])
                heures_raw = row[-1] if row else 0
                try: h = float(str(heures_raw).split('+')[0].strip())
                except: h = 0
                if h > 0 and mat and mat.lower() not in ['nan', 'total', '']:
                    assignments[cur].append({'formateur': v0, 'matiere': mat, 'heures': h, 'heures_faites': 0})

    ext = Path(filepath).suffix.lower()
    if ext == '.xls':
        try:
            wb = xlrd.open_workbook(filepath)
            si = next((i for i, n in enumerate(wb.sheet_names()) if 'mois' in n.lower()), len(wb.sheet_names())-1)
            ws = wb.sheet_by_index(si)
            process([[ws.cell_value(r, c) for c in range(ws.ncols)] for r in range(ws.nrows)])
        except: pass
    else:
        try:
            wb = load_workbook(filepath, data_only=True)
            sn = next((s for s in wb.sheetnames if 'mois' in s.lower()), wb.sheetnames[-1])
            process(list(wb[sn].iter_rows(values_only=True)))
        except: pass
    return dict(assignments)

# ─── Parseur tableau formateurs v2 (format tabulaire) ────────────────────────

def parse_tableau_formateurs_v2(filepath):
    """
    Parse le nouveau format d'affectations : 1 ligne = 1 affectation.

    Feuille cible : 'AFFECTATIONS' (ou première feuille si absente).
    En-tête auto-détecté dans les 10 premières lignes.

    Colonnes OBLIGATOIRES : CLASSE, FORMATEUR, MATIERE, HEURES_ANNEE
    Colonnes OPTIONNELLES : PRIORITE (défaut 1), NOTES (ignoré), ACTIF (défaut OUI)

    Retourne un dict compatible avec assigner() :
      { "BTS MCO 73": [
            {"formateur": "J.Christophe", "matiere": "Gestion",
             "heures": 100.0, "heures_faites": 0, "priorite": 1},
            ...
        ], ...
      }
    """
    try:
        wb = load_workbook(filepath, data_only=True)
    except Exception as e:
        raise ValueError(f"Impossible d'ouvrir {Path(filepath).name} : {e}")

    ws = wb['AFFECTATIONS'] if 'AFFECTATIONS' in wb.sheetnames else wb.active

    # ── Détecter la ligne d'en-tête ─────────────────────────────────────────
    header_row = None
    col_map    = {}
    for r in range(1, min(ws.max_row + 1, 10)):
        row_vals = [ws.cell(r, c).value for c in range(1, ws.max_column + 1)]
        upper    = [str(v).strip().upper() if v is not None else '' for v in row_vals]
        if 'CLASSE' in upper and 'FORMATEUR' in upper and 'MATIERE' in upper:
            header_row = r
            for i, label in enumerate(upper):
                if label:
                    col_map[label] = i + 1   # 1-indexé
            break

    if header_row is None:
        raise ValueError(
            "En-tête introuvable dans la feuille AFFECTATIONS. "
            "Colonnes attendues : CLASSE, FORMATEUR, MATIERE, HEURES_ANNEE"
        )

    # ── Valider les colonnes obligatoires ────────────────────────────────────
    manquantes = [col for col in ('CLASSE', 'FORMATEUR', 'MATIERE', 'HEURES_ANNEE')
                  if col not in col_map]
    if manquantes:
        raise ValueError(f"Colonnes obligatoires manquantes : {', '.join(manquantes)}")

    c_classe = col_map['CLASSE']
    c_form   = col_map['FORMATEUR']
    c_mat    = col_map['MATIERE']
    c_h      = col_map['HEURES_ANNEE']
    c_prio   = col_map.get('PRIORITE')
    c_actif  = col_map.get('ACTIF')

    # ── Lire les affectations ────────────────────────────────────────────────
    assignments = defaultdict(list)
    lignes_ignorees = 0

    for r in range(header_row + 1, ws.max_row + 1):
        classe    = ws.cell(r, c_classe).value
        formateur = ws.cell(r, c_form).value
        matiere   = ws.cell(r, c_mat).value
        heures_v  = ws.cell(r, c_h).value
        actif_v   = ws.cell(r, c_actif).value if c_actif else 'OUI'
        prio_v    = ws.cell(r, c_prio).value  if c_prio  else 1

        # Ignorer lignes vides
        if not (classe and formateur and matiere):
            continue

        # Ignorer lignes ACTIF = NON
        if str(actif_v or 'OUI').strip().upper() == 'NON':
            lignes_ignorees += 1
            continue

        # Valider et normaliser les heures (obligatoires, > 0)
        try:
            heures = float(str(heures_v).replace(',', '.').strip())
        except (TypeError, ValueError):
            lignes_ignorees += 1
            continue
        if heures <= 0:
            lignes_ignorees += 1
            continue

        # Normaliser la priorité
        try:
            priorite = int(prio_v) if prio_v else 1
        except (TypeError, ValueError):
            priorite = 1

        assignments[str(classe).strip()].append({
            'formateur':     str(formateur).strip(),
            'matiere':       str(matiere).strip(),
            'heures':        heures,
            'heures_faites': 0,        # requis par assigner()
            'priorite':      priorite, # pour tri — assigner() l'ignore
        })

    # Trier chaque classe par priorité (1 = principal avant 2 = remplaçant)
    for classe in assignments:
        assignments[classe].sort(key=lambda x: x['priorite'])

    # ── Log debug ────────────────────────────────────────────────────────────
    nb_classes     = len(assignments)
    nb_affectations = sum(len(v) for v in assignments.values())
    nb_formateurs  = len({a['formateur'] for v in assignments.values() for a in v})
    import logging
    logging.info(
        f"[parse_v2] {nb_classes} classes | {nb_formateurs} formateurs | "
        f"{nb_affectations} affectations | {lignes_ignorees} lignes ignorées"
    )
    # Exposé aussi en attribut pour que la route puisse le retourner si besoin
    result = dict(assignments)
    result['_debug'] = {
        'classes':      nb_classes,
        'formateurs':   nb_formateurs,
        'affectations': nb_affectations,
        'ignores':      lignes_ignorees,
    }
    return result


def _auto_parse_formateurs(filepath):
    """
    Sélecteur automatique : détecte le format du fichier et appelle
    le bon parseur.

    - Feuille AFFECTATIONS présente → parse_tableau_formateurs_v2()
    - Sinon → parse_tableau_formateurs() (ancien format matriciel)

    Permet une transition sans rupture : l'ancien fichier continue de
    fonctionner tant qu'il n'est pas remplacé.
    """
    try:
        wb     = load_workbook(filepath, data_only=True)
        sheets = wb.sheetnames
        wb.close()
        if 'AFFECTATIONS' in sheets:
            return parse_tableau_formateurs_v2(filepath)
    except Exception:
        pass
    return parse_tableau_formateurs(filepath)


# ─── Moteur assignation ───────────────────────────────────────────────────────
def _match_dispo(formateur_nom, dispo_idx):
    """Trouve les dispos d'un formateur par nom exact puis par matching partiel."""
    if formateur_nom in dispo_idx:
        return dispo_idx[formateur_nom]
    for key, val in dispo_idx.items():
        if noms_similaires(formateur_nom, key):
            return val
    return None  # None = pas de dispo trouvée (différent de {} = dispo vide)

def assigner(planning_classes, dispos_formateurs, affectations):
    dispo_idx = {d['nom']: d['dispo'] for d in dispos_formateurs}
    result = defaultdict(dict)
    stats = {'assigned': 0, 'warn': 0}
    # Suivi des formateurs déjà assignés : {(jour, slot): set(formateur)}
    deja_pris = defaultdict(set)

    SLOTS = ['matin1', 'matin2', 'pm1', 'pm2']

    for ci in planning_classes:
        cn = ci['nom']; jours = ci['jours']
        aff = next((v for k, v in affectations.items()
                    if noms_similaires(k, cn)), None)
        if not aff:
            for j in jours:
                result[j][cn] = {s: {'formateur': '?', 'matiere': '?'} for s in SLOTS}
            continue
        for j in jours:
            result[j][cn] = {}
            for slot in SLOTS:
                assigned = None
                for e in sorted(aff, key=lambda x: x['heures_faites']):
                    pd_ = _match_dispo(e['formateur'], dispo_idx)
                    if e['heures'] - e['heures_faites'] <= 0: continue
                    if pd_ is None: continue
                    jd = pd_.get(j, {})
                    if not jd.get(slot, False): continue
                    if e['formateur'] in deja_pris[(j, slot)]: continue
                    assigned = e; break
                if assigned:
                    assigned['heures_faites'] += 2
                    deja_pris[(j, slot)].add(assigned['formateur'])
                    result[j][cn][slot] = {'formateur': assigned['formateur'], 'matiere': assigned['matiere']}
                    stats['assigned'] += 1
                else:
                    result[j][cn][slot] = {'formateur': 'Pas de prof dispo', 'matiere': ''}
                    stats['warn'] += 1

    heures = defaultdict(lambda: defaultdict(int))
    for dv in result.values():
        for cl, slots in dv.items():
            for inf in slots.values():
                if inf['formateur'] not in ['?', 'Pas de prof dispo']:
                    heures[inf['formateur']][inf['matiere']] += 2
    return dict(result), stats, dict(heures)

# ─── Écriture planning assigné ────────────────────────────────────────────────
def ecrire_planning(template_path, assignment, mois_cibles, output_path):
    shutil.copy(template_path, output_path)
    wb = load_workbook(output_path)
    kw = ['BTS','BAC','EC ','CGC','NDRC','GPME','RDC','RH','Master','M3','M4','MCOM','BACHELOR','CARREFOUR']
    jf = {'lundi':0,'mardi':1,'mercredi':2,'jeudi':3,'vendredi':4,'lun':0,'mar':1,'mer':2,'jeu':3,'ven':4}

    for sn in wb.sheetnames:
        ws = wb[sn]; titre = ''
        # PATCH 8 — lecture titre robuste : cherche une cellule contenant un nom de mois
        # (pas juste la première cellule avec len>3, qui peut être le nom de l'école)
        for ri in range(1, 5):
            for ci in range(1, ws.max_column + 1):
                v = ws.cell(row=ri, column=ci).value
                if not (v and isinstance(v, str)): continue
                for m_key in MOIS_ABBR:
                    if m_key.upper() in v.upper():
                        titre = v.upper()
                        break
                if titre: break
            if titre: break
        # Fallback : utiliser le nom de l'onglet (ex: "Sept 2026")
        if not titre:
            titre = sn.upper()
        mn, yr = None, None
        for m, mnum in MOIS_ABBR.items():
            if m.upper() in titre:
                y = re.search(r'(20\d\d)', titre)
                if y: yr = int(y.group(1)); mn = mnum; break
        if not mn or f'{mn}/{yr}' not in mois_cibles: continue

        cc = {}
        for ri in range(1, 6):
            for ci in range(1, ws.max_column+1):
                v = ws.cell(row=ri, column=ci).value
                if isinstance(v, str) and any(k in v for k in kw): cc[v.strip()] = ci

        dr = {}
        for ri in range(1, ws.max_row+1):
            for ci in range(1, 4):
                v = ws.cell(row=ri, column=ci).value
                if isinstance(v, str) and v.strip().lower() in jf:
                    for lri in [ri, ri+1]:
                        for lci in range(1, 4):
                            dv = ws.cell(row=lri, column=lci).value
                            if isinstance(dv, (int, float)) and 1 <= int(dv) <= 31:
                                try:
                                    d = datetime.date(yr, mn, int(dv))
                                    ds = d.strftime('%Y-%m-%d')
                                    if ds not in dr: dr[ds] = ri
                                except: pass

        row_max_lines = {}  # { row_num: max nb lignes écrites }
        BLANC = {'00000000', 'FFFFFFFF', None}
        for ds, ri in dr.items():
            if ds not in assignment: continue
            for cn, ci in cc.items():
                for k, slots in assignment[ds].items():
                    if noms_similaires(k, cn):
                        # ri=label jour, donc: ri-1=matin1, ri=matin2, ri+1=pm1, ri+2=pm2
                        for slot, row in [('matin1', ri-1), ('matin2', ri), ('pm1', ri+1), ('pm2', ri+2)]:
                            sv = slots.get(slot, {})
                            f_ = sv.get('formateur', '')
                            m_ = sv.get('matiere', '')
                            cell = ws.cell(row=row, column=ci)
                            fg = cell.fill.fgColor if cell.fill else None
                            cell_color = fg.rgb if fg and fg.type == 'rgb' else None
                            if cell_color in BLANC:
                                continue
                            if f_ and f_ not in ('Pas de prof dispo', '?'):
                                cell.value = f'{f_}\n{m_}'
                                cell.font = Font(name='Calibri', size=8, color='FF000000')
                                cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
                                row_max_lines[row] = max(row_max_lines.get(row, 0), 2)
                            elif f_ == 'Pas de prof dispo':
                                cell.value = 'Pas de prof dispo'
                                cell.font = Font(name='Calibri', size=8, italic=True, color='FFFF0000')
                                cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
                                row_max_lines[row] = max(row_max_lines.get(row, 0), 1)
                        break
        # Ajuster la hauteur des lignes en fonction du contenu écrit
        for row, nb_lignes in row_max_lines.items():
            ws.row_dimensions[row].height = max(nb_lignes * 14, 16.8)
    wb.save(output_path)

# ─── Parser planning colorié ─────────────────────────────────────────────────
def parse_planning_colorie(filepath):
    """
    Lit un fichier colorié (produit par colorier_multifeuilles) et retourne
    une liste de {'nom': classe, 'jours': [dates]} — même format que parse_planning_classe.
    Détecte les colonnes de classes, puis cherche les cellules colorées pour chaque slot.
    """
    jf = {'lundi':0,'mardi':1,'mercredi':2,'jeudi':3,'vendredi':4,
          'lun':0,'mar':1,'mer':2,'jeu':3,'ven':4}
    try:
        wb = load_workbook(filepath, data_only=True)
    except Exception:
        return []

    classes_jours = defaultdict(set)

    for sn in wb.sheetnames:
        ws = wb[sn]
        mn, yr = None, None
        for src in [sn] + [ws.cell(row=r, column=c).value
                           for r in range(1, 4) for c in range(1, min(ws.max_column+1, 20))
                           if ws.cell(row=r, column=c).value]:
            if not isinstance(src, str): continue
            for m_key, m_num in MOIS_ABBR.items():
                if m_key.upper() in src.upper():
                    y = re.search(r'(20\d\d)', src)
                    if y:
                        mn = m_num; yr = int(y.group(1)); break
            if mn: break
        if not mn:
            continue

        struct = detect_structure(ws)
        cc = struct['class_cols']

        # Repérer les lignes slot : cherche nom de jour dans cols 1-4, numéro à ri+1
        row_dates = {}
        for ri in range(1, ws.max_row + 1):
            for ci2 in range(1, 5):
                v = ws.cell(row=ri, column=ci2).value
                if not isinstance(v, str) or v.strip().lower() not in jf: continue
                for lci in JOURS_COLS:
                    dv = ws.cell(row=ri + 1, column=lci).value
                    if isinstance(dv, (int, float)) and 1 <= int(dv) <= 31:
                        try:
                            d = datetime.date(yr, mn, int(dv))
                            if d not in row_dates:
                                row_dates[d] = ri
                        except: pass
                        break
                break

        # Pour chaque slot, vérifier quelles colonnes de classe sont colorées
        # ri = label jour, slot = 4 lignes : ri-1, ri, ri+1, ri+2
        BLANC = {'00000000', 'FFFFFFFF', None}
        for d, ri in row_dates.items():
            for classe_nom, col_idx in cc.items():
                for offset in range(-1, 3):
                    cell = ws.cell(row=ri + offset, column=col_idx)
                    if cell.fill and cell.fill.fgColor and cell.fill.fgColor.type == 'rgb':
                        if cell.fill.fgColor.rgb not in BLANC:
                            classes_jours[classe_nom].add(d.strftime('%Y-%m-%d'))
                            break

    wb.close()
    return [{'nom': nom, 'jours': sorted(jours)} for nom, jours in classes_jours.items()]

# ─── Génération template colorié (ancien) ────────────────────────────────────
_OFFICE_THEME_COLORS = [
    '000000','FFFFFF','1F497D','EEECE1','4F81BD','C0504D','9BBB59','8064A2','4BACC6','F79646',
]

def _resolve_fill_color(fill):
    if not fill or not fill.fgColor: return None
    fc = fill.fgColor
    if fc.type == 'rgb':
        c = fc.rgb
        return c if c not in ('00000000', 'FFFFFFFF') else None
    if fc.type == 'theme':
        base = _OFFICE_THEME_COLORS[fc.theme] if fc.theme < len(_OFFICE_THEME_COLORS) else '808080'
        t = fc.tint
        r, g, b = int(base[0:2],16), int(base[2:4],16), int(base[4:6],16)
        if t >= 0:
            r = int(r + (255-r)*t); g = int(g + (255-g)*t); b = int(b + (255-b)*t)
        else:
            r = int(r*(1+t)); g = int(g*(1+t)); b = int(b*(1+t))
        return 'FF{:02X}{:02X}{:02X}'.format(r, g, b)
    return None

def detect_structure(ws):
    kw = ['BTS','BAC','EC ','CGC','NDRC','GPME','RDC','RH','Master','M3','M4','MCOM','BACHELOR','CARREFOUR']
    cc = {}; colors = {}
    for ri in range(1, 6):
        for ci in range(1, ws.max_column+1):
            cell = ws.cell(row=ri, column=ci); v = cell.value
            if isinstance(v, str) and any(k in v for k in kw):
                nom = v.strip(); cc[nom] = ci
                c = _resolve_fill_color(cell.fill)
                if c: colors[nom] = c
    for nom, ci in cc.items():
        if nom in colors: continue
        for ri in range(5, min(25, ws.max_row+1)):
            c = _resolve_fill_color(ws.cell(row=ri, column=ci).fill)
            if c: colors[nom] = c; break
    jf_set = {'lundi','mardi','mercredi','jeudi','vendredi','lun','mar','mer','jeu','ven'}
    fdr = 6; dlc = 2
    for ri in range(3, 20):
        for ci in range(1, 5):
            v = ws.cell(row=ri, column=ci).value
            if isinstance(v, str) and v.strip().lower() in jf_set:
                fdr = ri; dlc = ci; break
        else: continue
        break
    return {'class_cols': cc, 'class_colors': colors, 'first_data_row': fdr, 'day_label_col': dlc}

_ALIAS_CLASSES = {
    'M3': ['MCOM 3', 'MCOM3', 'MASTER 3', 'MASTERE 3'],
    'M4': ['MCOM 4', 'MCOM4', 'MASTER 4', 'MASTERE 4'],
}
_ALIAS_REVERSE = {alias.upper(): canon for canon, aliases in _ALIAS_CLASSES.items() for alias in aliases}

def _strip_accents(s):
    import unicodedata as _ud
    return ''.join(c for c in _ud.normalize('NFD', s) if _ud.category(c) != 'Mn')

def _normalise_nom(n):
    import re as _re
    nu = _strip_accents(n.strip()).upper()
    # Supprimer les formes féminines entre parenthèses ex: (E) ou (LE)
    nu = _re.sub(r'\([A-Z]{1,4}\)', '', nu)
    # Supprimer mots parasites
    for w in ['PLANNING','BACHELOR','COMMERCE','CONTRAT','APP','VERSION','MODIFIE','JUILLET',
              'EUROPEEN','TITRE','PRO','CFA']:
        nu = _re.sub(r'\b' + w + r'\b', '', nu)
    # Remplacer MCOM/MASTERE par M
    nu = _re.sub(r'\bMCOM\b', 'M', nu)
    nu = _re.sub(r'\bMASTERE?\b', 'M', nu)
    # Séparer M3/M4 en "M 3"/"M 4" pour que le numéro soit extrait séparément
    nu = _re.sub(r'\bM(\d+)\b', r'M \1', nu)
    return nu.strip()

def _acronyme_match(short_word, long_words):
    """Vérifie si short_word est un acronyme formé par les initiales de long_words.
    Ex: 'EC' matches ['EMPLOYE','COMMERCIAL'], 'RDC' matches ['RESPONSABLE','DEVELOPPEMENT','COMMERCIAL']"""
    initials = ''.join(w[0] for w in long_words if w)
    return short_word in initials or initials.startswith(short_word)

def noms_similaires(a, b):
    """Retourne True si deux noms désignent probablement la même entité.
    - Avec numéros (classes) : numéro commun + mot commun ou acronyme commun
    - Sans numéros (formateurs) : au moins 2 mots significatifs en commun"""
    import re as _re
    # Alias explicites M3/M4
    au, bu = a.strip().upper(), b.strip().upper()
    if _ALIAS_REVERSE.get(au) == bu or _ALIAS_REVERSE.get(bu) == au: return True
    # Normaliser avant comparaison
    a, b = _normalise_nom(a), _normalise_nom(b)
    STOP = {'DE','DU','LE','LA','LES','ET','EN','PAR','POUR','SUR','AU','AUX',
            'TABLEAU','PLANNING','DISPONIBILITES','DISPONIBILITE','DISPONIBILITES'}
    nums_a = set(_re.findall(r'\d+', a))
    nums_b = set(_re.findall(r'\d+', b))
    words_a = [w.upper() for w in _re.findall(r'[A-Za-z]+', a) if w.upper() not in STOP]
    words_b = [w.upper() for w in _re.findall(r'[A-Za-z]+', b) if w.upper() not in STOP]
    set_a, set_b = set(words_a), set(words_b)
    common_words = set_a & set_b
    if nums_a and nums_b:
        if not (nums_a & nums_b): return False
        if common_words: return True
        if not set_a and not set_b: return True
        # Vérifier si un mot court (≤5 lettres) dans l'un est acronyme des mots de l'autre
        short_a = [w for w in set_a if len(w) <= 5]
        short_b = [w for w in set_b if len(w) <= 5]
        for sw in short_a:
            if _acronyme_match(sw, words_b): return True
        for sw in short_b:
            if _acronyme_match(sw, words_a): return True
        return False
    else:
        # Noms sans numéros (formateurs) : au moins 2 mots significatifs communs
        # OU 1 mot commun si l'un des noms est court (≤3 mots)
        min_words = min(len(set_a), len(set_b))
        return len(common_words) >= 2 or (len(common_words) >= 1 and min_words <= 3)

def _build_jours_json(planning_classes, json_path):
    """Construit le dict {date: [noms_classes]} et le sauvegarde en JSON."""
    import json as _json
    jours_par_date = defaultdict(list)
    for pc in planning_classes:
        for ds in pc.get('jours', []):
            if pc['nom'] not in jours_par_date[ds]:
                jours_par_date[ds].append(pc['nom'])
    with open(json_path, 'w', encoding='utf-8') as f:
        _json.dump(dict(sorted(jours_par_date.items())), f, ensure_ascii=False, indent=2)
    return jours_par_date

def colorier_multifeuilles(multi_path, planning_classes, output_path):
    """
    Nouveau flux : reçoit un Excel multi-feuilles (produit par generer_excel_multifeuilles)
    et colorie directement les cases de chaque classe jour par jour.

    - Construit d'abord un JSON {date: [classes]} dans le même dossier que output_path
    - Détecte le mois/année depuis le titre de chaque feuille (ex. "Septembre 2026")
    - Détecte la structure (colonnes classes, ligne de début, colonne jour) via detect_structure
    - Repère les lignes de données en cherchant le nom du jour + numéro dans les premières colonnes
    - Colorie les cases des classes qui ont cours ce jour-là
    """
    import json as _json
    shutil.copy(multi_path, output_path)
    wb = load_workbook(output_path)

    # Étape 1 : parser toutes les plannings → JSON intermédiaire
    json_path = os.path.join(os.path.dirname(output_path), 'jours_cours.json')
    jours_par_date = _build_jours_json(planning_classes, json_path)
    # Relire depuis le JSON (source de vérité)
    with open(json_path, encoding='utf-8') as f:
        jours_par_date = {k: set(v) for k, v in _json.load(f).items()}

    jf = {'lundi':0,'mardi':1,'mercredi':2,'jeudi':3,'vendredi':4,
          'lun':0,'mar':1,'mer':2,'jeu':3,'ven':4}
    total = 0

    for sn in wb.sheetnames:
        ws = wb[sn]

        # Détecter mois/année depuis le titre de la feuille ou cellules en-tête
        mn, yr = None, None
        for src in [sn] + [ws.cell(row=r, column=c).value
                            for r in range(1, 4) for c in range(1, ws.max_column+1)
                            if ws.cell(row=r, column=c).value]:
            if not isinstance(src, str): continue
            for m_key, m_num in MOIS_ABBR.items():
                if m_key.upper() in src.upper():
                    y = re.search(r'(20\d\d)', src)
                    if y:
                        mn = m_num; yr = int(y.group(1)); break
            if mn: break
        if not mn:
            continue

        struct = detect_structure(ws)
        cc = struct['class_cols']; colors = struct['class_colors']
        ci_def = 0
        for nom in cc:
            if nom not in colors:
                colors[nom] = DEFAULT_COLORS[ci_def % len(DEFAULT_COLORS)]; ci_def += 1

        # Repérer les lignes de données : cherche label jour dans JOURS_COLS
        # Structure slot : rl+0=séparateur, rl+1=label, rl+2=num, rl+3=contenu
        row_dates = {}  # { 'YYYY-MM-DD': rl }  rl = row du séparateur (slot+0)
        for ri in range(1, ws.max_row + 1):
            for lci in JOURS_COLS:
                v = ws.cell(row=ri, column=lci).value
                if not isinstance(v, str): continue
                if v.strip().lower() not in jf: continue
                dv = ws.cell(row=ri + 1, column=lci).value
                if isinstance(dv, (int, float)) and 1 <= int(dv) <= 31:
                    try:
                        d = datetime.date(yr, mn, int(dv))
                        ds = d.strftime('%Y-%m-%d')
                        if ds not in row_dates:
                            row_dates[ds] = ri - 1  # rl = ligne séparateur = ri-1
                    except: pass
                break

        # Colorier uniquement — 4 lignes par slot (rl+0 à rl+3), sans toucher aux valeurs
        for ds, rl in row_dates.items():
            classes_ce_jour = jours_par_date.get(ds, set())
            for classe_nom, col_idx in cc.items():
                a_cours = any(
                    noms_similaires(pc_nom, classe_nom)
                    for pc_nom in classes_ce_jour
                )
                if a_cours:
                    color = colors.get(classe_nom, 'FFD9D9D9')
                    if len(color) == 6: color = 'FF' + color
                    fill_on = PatternFill(start_color=color, end_color=color, fill_type='solid')
                    for offset in range(4):
                        ws.cell(row=rl + offset, column=col_idx).fill = fill_on
                    total += 1

    wb.save(output_path)
    return total, len(wb.sheetnames)


def generer_template_colorie(template_path, planning_classes, annee_debut, output_path, mois_cibles=None):
    wb_tpl = load_workbook(template_path)
    struct = detect_structure(wb_tpl.active)
    cc = struct['class_cols']; colors = struct['class_colors']
    fdr = struct['first_data_row']; dlc = struct['day_label_col']

    ci = 0
    for nom in cc:
        if nom not in colors:
            colors[nom] = DEFAULT_COLORS[ci % len(DEFAULT_COLORS)]; ci += 1

    mois_scolaire_all = [(9,annee_debut),(10,annee_debut),(11,annee_debut),(12,annee_debut),
                          (1,annee_debut+1),(2,annee_debut+1),(3,annee_debut+1),(4,annee_debut+1),
                          (5,annee_debut+1),(6,annee_debut+1),(7,annee_debut+1),(8,annee_debut+1)]
    if mois_cibles:
        cibles_set = {(int(m2), int(a2)) for a2, m2 in mois_cibles}
        mois_scolaire = [(m2, a2) for m2, a2 in mois_scolaire_all if (m2, a2) in cibles_set]
    else:
        mois_scolaire = mois_scolaire_all
    jf_nom = {0:'Lundi',1:'Mardi',2:'Mercredi',3:'Jeudi',4:'Vendredi'}

    wb_out = Workbook(); wb_out.remove(wb_out.active)
    total = 0

    for (mois, annee) in mois_scolaire:
        wb_tmp = load_workbook(template_path); ws_src = wb_tmp.active
        ws = wb_out.create_sheet(title=f"{MOIS_FR[mois]} {annee}")

        for row in ws_src.iter_rows():
            for cell in row:
                nc = ws.cell(row=cell.row, column=cell.column)
                nc.value = cell.value
                if cell.has_style:
                    nc.font = copy.copy(cell.font); nc.fill = copy.copy(cell.fill)
                    nc.border = copy.copy(cell.border); nc.alignment = copy.copy(cell.alignment)
                    nc.number_format = cell.number_format
        for cl, cd in ws_src.column_dimensions.items():
            ws.column_dimensions[cl].width = cd.width
        for ri, rd in ws_src.row_dimensions.items():
            ws.row_dimensions[ri].height = rd.height
        # APRÈS — Bug #2 corrigé : bypass ws.merge_cells() O(n²) → CellRange direct
        from openpyxl.worksheet.cell_range import CellRange as _CR
        _seen = set()
        for mg in ws_src.merged_cells.ranges:
            k = str(mg)
            if k not in _seen:
                _seen.add(k)
                try: ws.merged_cells.ranges.add(_CR(k))
                except: pass

        for ri in range(1, 4):
            for ci2 in range(1, ws.max_column+1):
                v = ws.cell(row=ri, column=ci2).value
                if isinstance(v, str) and re.search(r'20\d\d', v):
                    ws.cell(row=ri, column=ci2).value = f"{MOIS_FR[mois].upper()} {annee}"

        nb_j = calendar.monthrange(annee, mois)[1]
        jours_ouvres = [datetime.date(annee, mois, j) for j in range(1, nb_j+1)
                        if datetime.date(annee, mois, j).weekday() < 5
                        and datetime.date(annee, mois, j) not in FERIES]

        row_idx = fdr
        for d in jours_ouvres:
            ds = d.strftime('%Y-%m-%d')
            ws.cell(row=row_idx, column=dlc).value = jf_nom[d.weekday()]
            ws.cell(row=row_idx, column=dlc+1).value = d.day
            for classe_nom, col_idx in cc.items():
                a_cours = any(
                    ds in pc['jours']
                    for pc in planning_classes
                    if pc['nom'] and (pc['nom'].strip().lower() in classe_nom.lower()
                                      or classe_nom.lower() in pc['nom'].strip().lower())
                )
                cell = ws.cell(row=row_idx, column=col_idx)
                if a_cours:
                    color = colors.get(classe_nom, 'FFD9D9D9')
                    if len(color) == 6: color = 'FF' + color
                    cell.fill = PatternFill(start_color=color, end_color=color, fill_type='solid')
                    total += 1
                else:
                    cell.fill = PatternFill(fill_type=None); cell.value = None
            row_idx += 1

    wb_out.save(output_path)
    return total, len(mois_scolaire)

# ─── Génération d'un mois ────────────────────────────────────────────────────

def _ecrire_titre_mois(ws, annee, mois):
    """Remplace le mois/année dans les cellules titre (lignes 1-3)."""
    import re as _re
    nom_mois = MOIS_FR_UPPER[mois]
    pattern  = (r'(?:JANVIER|FÉVRIER|FEVRIER|MARS|AVRIL|MAI|JUIN|JUILLET|'
                r'AOÛT|AOUT|SEPTEMBRE|OCTOBRE|NOVEMBRE|DÉCEMBRE|DECEMBRE) 20\d\d')
    for r in range(1, 4):
        for col in range(1, ws.max_column + 1):
            v = ws.cell(row=r, column=col).value
            if not isinstance(v, str): continue
            if _re.search(pattern, v.upper()):
                ws.cell(row=r, column=col).value = _re.sub(
                    pattern, f"{nom_mois} {annee}", v.upper(), flags=_re.IGNORECASE)

def _jours_ouvres_mois(annee, mois):
    """Retourne la liste des (label_jour, num_jour) ouvrés du mois."""
    jours = []
    for j in range(1, calendar.monthrange(annee, mois)[1] + 1):
        d = datetime.date(annee, mois, j)
        if d.weekday() < 5:
            jours.append((JOURS_FR_LIST[d.weekday()], j))
    return jours

def _slot_debut(annee, mois):
    """Nombre de slots à sauter en début de mois (0 = lundi, 4 = vendredi)."""
    premier = datetime.date(annee, mois, 1)
    return premier.weekday() if premier.weekday() < 5 else 0


def _get_separateurs_sections(ws):
    """
    Détecte dynamiquement les colonnes séparatrices entre sections (ex: P, AJ, AZ).
    Critère : colonne de largeur > 1 char sans aucune bordure sur la ligne de contenu (row 9).
    Retourne un set de numéros de colonnes et un dict {num: lettre}.
    """
    from openpyxl.utils import get_column_letter as _gcl
    seps = set()
    seps_lettres = {}
    for c in range(1, ws.max_column + 1):
        w = ws.column_dimensions[_gcl(c)].width
        if w is None or w <= 1:
            continue
        cell = ws.cell(9, c)
        b = cell.border if cell.has_style else None
        has_border = b and (b.left.border_style or b.right.border_style or b.bottom.border_style)
        if not has_border:
            seps.add(c)
            seps_lettres[c] = _gcl(c)
    return seps, seps_lettres


def _corriger_bordures_thin(ws, closing_row):
    """
    Sur chaque slot, l'offset +1 (2ème ligne) doit avoir bottom=thin.
    Détecte les débuts de slot dynamiquement par la hauteur h=11.4 (top=medium)
    pour être robuste après suppressions de lignes.
    """
    from openpyxl.styles import Border, Side
    from openpyxl.utils import get_column_letter as _gcl

    # Détecter les colonnes à ignorer
    _seps = set()
    _etroits = set()
    for _c in range(1, ws.max_column + 1):
        _w = ws.column_dimensions[_gcl(_c)].width
        if _w is None or _w <= 1:
            _etroits.add(_c)
        else:
            _cell9 = ws.cell(9, _c)
            _b9 = _cell9.border if _cell9.has_style else None
            if not (_b9 and (_b9.left.border_style or _b9.right.border_style or _b9.bottom.border_style)):
                _seps.add(_c)
    _cols_classes = [c for c in range(1, ws.max_column + 1)
                     if c not in JOURS_COLS and c not in _seps and c not in _etroits]

    # Détecter les débuts de slot par hauteur h=11.4
    _debuts_slots = []
    for r in range(6, closing_row):
        h = ws.row_dimensions[r].height
        if h is not None and abs(h - 11.4) < 0.5:
            _debuts_slots.append(r)

    _thin = Side(border_style='thin')
    for rl in _debuts_slots:
        r = rl + 1  # offset +1 : la ligne qui doit avoir bottom=thin
        if r >= closing_row:
            break
        for _c in _cols_classes:
            cell = ws.cell(r, _c)
            b = cell.border
            cell.border = Border(
                left=b.left, right=b.right, top=b.top,
                bottom=_thin,
            )


def generate_month_sheet_delete(ws, annee, mois):
    """
    Supprime les slots inutilisés et écrit les jours du mois.
    closing_row = séparateur de semaine qui suit le dernier jour (h=7.2, top+bot=medium)
                + border_bottom=medium ajouté sur toutes les colonnes.
    """
    from openpyxl.worksheet.cell_range import CellRange
    from openpyxl.styles import Border, Side

    jours_ouvres = _jours_ouvres_mois(annee, mois)
    if not jours_ouvres:
        raise ValueError(f"Aucun jour ouvré pour {mois}/{annee}")
    slot_deb = _slot_debut(annee, mois)
    nb_jours = len(jours_ouvres)

    _ecrire_titre_mois(ws, annee, mois)

    # ── Effacer les valeurs résiduelles dans tous les slots ──────────────────
    for rl in SLOT_ROWS:
        for col in JOURS_COLS:
            for offset in range(4):
                ws.cell(row=rl + offset, column=col).value = None

    # ── Supprimer le HAUT en premier (slot_deb * 4 lignes depuis row 7) ─────
    # On supprime depuis row 7 pour préserver row 6 (séparateur, border_top=medium)
    SEPS_TEMPLATE = [6 + w * 21 + 20 for w in range(5)]  # [26, 47, 68, 89, 110]
    if slot_deb > 0:
        lignes_haut = slot_deb * 4
        saved_heights = {r: ws.row_dimensions[r].height
                         for r in range(7 + lignes_haut, TEMPLATE_LAST_ROW + 1)}
        ws.delete_rows(7, lignes_haut)
        for old_r, h in saved_heights.items():
            new_r = old_r - lignes_haut
            if new_r >= 7 and h is not None:
                ws.row_dimensions[new_r].height = h
        target_rows = {r for r in range(6, ws.max_row + 1)
                       if (ws.row_dimensions[r].height is None
                           or ws.row_dimensions[r].height >= 10)}
        for mg in list(ws.merged_cells.ranges):
            if mg.min_row == mg.max_row and mg.min_row in target_rows:
                try: ws.merged_cells.ranges.discard(mg)
                except Exception: pass
        for r in target_rows:
            for c1, c2 in ALL_MERGE_PAIRS:
                ws.merged_cells.ranges.add(
                    CellRange(f"{get_column_letter(c1)}{r}:{get_column_letter(c2)}{r}"))

    # ── Écrire les jours avec positions décalées ─────────────────────────────
    _font_date = Font(bold=True, size=12)
    lignes_haut = slot_deb * 4
    for i, (label, num) in enumerate(jours_ouvres):
        rl = SLOT_ROWS[slot_deb + i] - lignes_haut
        ws.row_dimensions[rl].height = 11.4
        for col in JOURS_COLS:
            c_label = ws.cell(row=rl + 1, column=col)
            c_label.value = label
            c_label.font = _font_date
            c_num = ws.cell(row=rl + 2, column=col)
            c_num.value = num
            c_num.font = _font_date

    # ── Supprimer le BAS en deux passes ──────────────────────────────────────
    last_slot_idx = slot_deb + nb_jours - 1
    last_slot_end = SLOT_ROWS[last_slot_idx] - lignes_haut + 3
    semaine = last_slot_idx // 5
    closing_row = SEPS_TEMPLATE[semaine] - lignes_haut

    # Passe A : slots vides entre le dernier jour et la closing_row
    slots_vides = closing_row - 1 - last_slot_end
    if slots_vides > 0:
        ws.delete_rows(last_slot_end + 1, slots_vides)
        closing_row = last_slot_end + 1

    # Passe B : semaines inutilisées après closing_row
    delete_from  = closing_row + 1
    delete_until = TEMPLATE_LAST_ROW - lignes_haut
    if delete_from <= delete_until:
        ws.delete_rows(delete_from, delete_until - delete_from + 1)

    # ── Purger les fantômes au-delà de closing_row ───────────────────────────
    for key in [k for k in ws._cells if k[0] > closing_row]:
        del ws._cells[key]
    for phantom_r in [r for r in ws.row_dimensions if r > closing_row]:
        del ws.row_dimensions[phantom_r]
    for mg in list(ws.merged_cells.ranges):
        if mg.min_row > closing_row or mg.max_row > closing_row:
            ws.merged_cells.ranges.discard(mg)

    # ── Largeur colonnes dates : ajuster au contenu ──────────────────────────
    for _dc in JOURS_COLS:
        max_len = max((len(str(ws.cell(r, _dc).value)) for r in range(6, closing_row)
                       if ws.cell(r, _dc).value is not None), default=4)
        ws.column_dimensions[get_column_letter(_dc)].width = max_len + 2

    # ── Uniformiser largeur colonnes classes ─────────────────────────────────
    _seps_sections = set()
    _seps_etroits = set()
    for _c in range(1, ws.max_column + 1):
        _w = ws.column_dimensions[get_column_letter(_c)].width
        if _w is None or _w <= 1:
            _seps_etroits.add(_c)
        else:
            _cell9 = ws.cell(9, _c)
            _b9 = _cell9.border if _cell9.has_style else None
            if not (_b9 and (_b9.left.border_style or _b9.right.border_style or _b9.bottom.border_style)):
                _seps_sections.add(_c)
    for _c in range(1, ws.max_column + 1):
        if _c not in JOURS_COLS and _c not in _seps_sections and _c not in _seps_etroits:
            ws.column_dimensions[get_column_letter(_c)].width = 20

    # ── Corriger les bordures thin manquantes dans les slots ─────────────────
    _corriger_bordures_thin(ws, closing_row)

    # ── Hauteur closing_row = 7.2 ────────────────────────────────────────────
    ws.row_dimensions[closing_row].height = 7.2

    # ── Ajouter border_bottom=medium sur les colonnes de classes uniquement ───
    _seps_sections, _ = _get_separateurs_sections(ws)
    _CLOSING_COLS = [c for c in range(1, ws.max_column + 1) if c not in _seps_sections]
    for _c in _CLOSING_COLS:
        cell = ws.cell(closing_row, _c)
        b = cell.border
        cell.border = Border(
            left=b.left, right=b.right, top=b.top,
            bottom=Side(border_style='medium'),
        )

    # ── Fill gris sur les séparateurs entre semaines (pas la closing row) ────
    from openpyxl.styles.colors import Color as _Color
    _grey_fill = PatternFill(fill_type='solid',
                             fgColor=_Color(theme=0, tint=-0.249977111117893, type='theme'))
    _SEP_COLS_BLANCHES, _ = _get_separateurs_sections(ws)
    lignes_debut = slot_deb * 4
    for _sep in SEPS_TEMPLATE:
        _sep_shifted = _sep - lignes_debut
        if _sep_shifted >= 6 and _sep_shifted < closing_row:
            for _c in range(1, ws.max_column + 1):
                if _c not in _SEP_COLS_BLANCHES:
                    ws.cell(_sep_shifted, _c).fill = _grey_fill

    return nb_jours



# ─── Génération template vierge par mois ─────────────────────────────────────
def _supprimer_lignes_masquees_xml(xlsx_path):
    """
    Post-traitement XML : supprime physiquement les lignes height=0 d'un fichier xlsx.
    Bypasse openpyxl (delete_rows O(n²)) en manipulant directement le ZIP/XML.
    Les merged cells qui chevauchent ces lignes sont aussi retirées.
    """
    import zipfile, io
    from xml.etree import ElementTree as ET

    NS = 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'
    ET.register_namespace('', NS)

    with zipfile.ZipFile(xlsx_path, 'r') as zin:
        names  = zin.namelist()
        blobs  = {n: zin.read(n) for n in names}

    # Feuille active = xl/worksheets/sheet1.xml (ou sheet avec idx le plus bas)
    sheet_names = sorted(
        [n for n in names if n.startswith('xl/worksheets/sheet') and n.endswith('.xml')],
        key=lambda x: int(re.search(r'(\d+)', x.split('/')[-1]).group(1))
    )
    if not sheet_names:
        return

    sheet_name = sheet_names[0]
    tree = ET.fromstring(blobs[sheet_name])

    # 1. Identifier les numéros de lignes à supprimer (ht="0")
    rows_tag   = f'{{{NS}}}row'
    merged_tag = f'{{{NS}}}mergeCells'
    mc_tag     = f'{{{NS}}}mergeCell'

    hidden_rows = set()
    sheetData   = tree.find(f'{{{NS}}}sheetData')
    if sheetData is None:
        return

    rows_to_remove = []
    for row_el in sheetData:
        if row_el.tag != rows_tag:
            continue
        ht = row_el.get('ht')
        if ht is not None and float(ht) == 0:
            hidden_rows.add(int(row_el.get('r', 0)))
            rows_to_remove.append(row_el)

    for row_el in rows_to_remove:
        sheetData.remove(row_el)

    if not hidden_rows:
        return  # rien à faire

    # 2. Renuméroter les lignes restantes
    sorted_hidden = sorted(hidden_rows)
    row_els = [el for el in sheetData if el.tag == rows_tag]
    for row_el in row_els:
        old_r = int(row_el.get('r'))
        shift = sum(1 for h in sorted_hidden if h < old_r)
        if shift == 0:
            continue
        new_r = old_r - shift
        row_el.set('r', str(new_r))
        for cell_el in row_el:
            coord = cell_el.get('r', '')
            col_part = ''.join(c for c in coord if c.isalpha())
            if col_part:
                cell_el.set('r', f'{col_part}{new_r}')

    # 3. Nettoyer les mergeCells qui chevauchent les lignes supprimées
    def _shift_row(r):
        return r - sum(1 for h in sorted_hidden if h < r)

    for mc_parent in tree.iter(merged_tag):
        to_remove = []
        for mc in mc_parent:
            if mc.tag != mc_tag:
                continue
            ref = mc.get('ref', '')
            m = re.match(r'([A-Z]+)(\d+):([A-Z]+)(\d+)', ref)
            if not m:
                continue
            c1, r1, c2, r2 = m.group(1), int(m.group(2)), m.group(3), int(m.group(4))
            # Supprimer si une des lignes est cachée
            if any(r1 <= h <= r2 for h in hidden_rows):
                to_remove.append(mc)
            else:
                new_r1 = _shift_row(r1)
                new_r2 = _shift_row(r2)
                if new_r1 != r1 or new_r2 != r2:
                    mc.set('ref', f'{c1}{new_r1}:{c2}{new_r2}')
        for mc in to_remove:
            mc_parent.remove(mc)

    # 4. Réécrire le ZIP
    new_xml = ET.tostring(tree, encoding='UTF-8', xml_declaration=True)
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED) as zout:
        for n in names:
            if n == sheet_name:
                zout.writestr(n, new_xml)
            else:
                zout.writestr(n, blobs[n])
    buf.seek(0)
    with open(xlsx_path, 'wb') as f:
        f.write(buf.read())


def generer_template_mois(template_path, output_path, annee, mois):
    """Génère un template vierge pour un mois donné dans output_path."""
    import base64 as _b64, io as _io
    wb = load_workbook(_io.BytesIO(_b64.b64decode(_TEMPLATE_VIERGE_B64)))
    ws = wb.active
    nb = _appliquer_mois_sur_feuille(ws, annee, mois)
    wb.save(output_path)
    return nb


# ─── Excel multi-feuilles (une feuille par mois) ─────────────────────────────
def _copier_feuille(ws_src, ws_dst):
    """
    Copie complète d'une feuille vers une autre (workbooks différents).
    Recrée les styles via leurs constructeurs pour éviter copy.copy() cassé sur Python 3.14+.
    """
    from openpyxl.styles import Font, PatternFill, Border, Side, Alignment
    max_row = ws_src.max_row
    for row in ws_src.iter_rows(max_row=max_row):
        for cell in row:
            nc = ws_dst.cell(row=cell.row, column=cell.column)
            nc.value = cell.value
            if cell.has_style:
                f = cell.font
                nc.font = Font(
                    name=f.name, size=f.size, bold=f.bold, italic=f.italic,
                    underline=f.underline, color=copy.copy(f.color),
                    strike=f.strike, vertAlign=f.vertAlign
                )
                fi = cell.fill
                nc.fill = PatternFill(
                    fill_type=fi.fill_type,
                    fgColor=copy.copy(fi.fgColor),
                    bgColor=copy.copy(fi.bgColor)
                )
                b = cell.border
                def _side(s):
                    return Side(border_style=s.border_style, color=copy.copy(s.color))
                nc.border = Border(
                    left=_side(b.left), right=_side(b.right),
                    top=_side(b.top), bottom=_side(b.bottom)
                )
                a = cell.alignment
                nc.alignment = Alignment(
                    horizontal=a.horizontal, vertical=a.vertical,
                    wrap_text=a.wrap_text, indent=a.indent
                )
                nc.number_format = cell.number_format
    for col, cd in ws_src.column_dimensions.items():
        ws_dst.column_dimensions[col].width = cd.width
    for r, rd in ws_src.row_dimensions.items():
        if rd.height and r <= max_row:
            ws_dst.row_dimensions[r].height = rd.height
    from openpyxl.worksheet.cell_range import CellRange
    seen = set()
    for mg in ws_src.merged_cells.ranges:
        if mg.min_row > max_row or mg.max_row > max_row:
            continue
        k = str(mg)
        if k not in seen:
            seen.add(k)
            try:
                ws_dst.merged_cells.ranges.add(CellRange(k))
            except Exception:
                pass


def generer_excel_multifeuilles(template_path, mois_liste, output_path):
    """Génère un Excel multi-feuilles (1 onglet par mois)."""
    import tempfile

    wb_out = Workbook()
    wb_out.remove(wb_out.active)
    total_jours = 0

    for (annee, mois) in mois_liste:
        with tempfile.NamedTemporaryFile(suffix='.xlsx', delete=False) as tmp:
            tmp_path = tmp.name
        nb_jours = generer_template_mois(template_path, tmp_path, annee, mois)
        total_jours += nb_jours

        wb_tmp = load_workbook(tmp_path)
        ws_src = wb_tmp.active
        sheet_name = f"{MOIS_FR[mois][:4]} {annee}"
        ws_dst = wb_out.create_sheet(title=sheet_name)
        _copier_feuille(ws_src, ws_dst)
        wb_tmp.close()
        os.unlink(tmp_path)

    wb_out.save(output_path)
    return total_jours

# ─── Fusion de fichiers Excel ─────────────────────────────────────────────────
def _copier_feuille(ws_src, ws_dst):
    """
    Copie complète d'une feuille vers une autre (workbooks différents).
    Copie valeurs, styles complets (font, fill, border, alignment) et dimensions.
    """
    from openpyxl.worksheet.cell_range import CellRange
    from openpyxl.styles import Font, PatternFill, Border, Side, Alignment
    MAX_COL = 130
    max_row = ws_src.max_row

    for (row, col), cell in ws_src._cells.items():
        if col > MAX_COL or row > max_row:
            continue
        if not cell.has_style and cell.value is None:
            continue

        nc = ws_dst.cell(row=row, column=col, value=cell.value)

        if cell.has_style:
            f = cell.font
            nc.font = Font(name=f.name, size=f.size, bold=f.bold, italic=f.italic,
                           underline=f.underline, color=copy.copy(f.color),
                           strike=f.strike, vertAlign=f.vertAlign)
            fi = cell.fill
            nc.fill = PatternFill(fill_type=fi.fill_type,
                                  fgColor=copy.copy(fi.fgColor),
                                  bgColor=copy.copy(fi.bgColor))
            b = cell.border
            nc.border = Border(
                left=Side(border_style=b.left.border_style, color=copy.copy(b.left.color)),
                right=Side(border_style=b.right.border_style, color=copy.copy(b.right.color)),
                top=Side(border_style=b.top.border_style, color=copy.copy(b.top.color)),
                bottom=Side(border_style=b.bottom.border_style, color=copy.copy(b.bottom.color)),
            )
            a = cell.alignment
            nc.alignment = Alignment(horizontal=a.horizontal, vertical=a.vertical,
                                     wrap_text=a.wrap_text, indent=a.indent)
            nc.number_format = cell.number_format

    for col, cd in ws_src.column_dimensions.items():
        ws_dst.column_dimensions[col].width = cd.width
    for r, rd in ws_src.row_dimensions.items():
        if r <= max_row:
            if rd.height is not None:
                ws_dst.row_dimensions[r].height = rd.height
            if rd.hidden:
                ws_dst.row_dimensions[r].hidden = True
    seen = set()
    for mg in ws_src.merged_cells.ranges:
        if mg.min_row > max_row or mg.max_row > max_row:
            continue
        k = str(mg)
        if k not in seen:
            seen.add(k)
            try:
                ws_dst.merged_cells.ranges.add(CellRange(k))
            except Exception:
                pass


def fusionner_excels(sources, noms_feuilles=None):
    """
    Fusionne plusieurs fichiers Excel (une feuille chacun) en un seul fichier multi-feuilles.
    sources       : list[bytes | str | Path]
    noms_feuilles : list[str] optionnel — noms des onglets dans le fichier final
    Retourne bytes.
    """
    from io import BytesIO
    wb_dest = Workbook()
    wb_dest.remove(wb_dest.active)
    used_names = []

    for i, source in enumerate(sources):
        if isinstance(source, (bytes, bytearray)):
            wb_src = load_workbook(BytesIO(source))
        else:
            wb_src = load_workbook(source)

        ws_src = wb_src.active
        raw = (noms_feuilles[i].strip()
               if noms_feuilles and i < len(noms_feuilles) and noms_feuilles[i].strip()
               else ws_src.title)
        nom = raw[:31]
        if nom in used_names:
            nom = f"{nom[:27]}_{i+1}"
        used_names.append(nom)

        ws_dst = wb_dest.create_sheet(title=nom)
        _copier_feuille(ws_src, ws_dst)
        wb_src.close()

    out = BytesIO()
    wb_dest.save(out)
    return out.getvalue()

